mapper.select:
SELECT * FROM daily_report r1
WHERE r1.day_offset = #{dayOffset}
AND r1.base_date = (
SELECT MAX(r2.base_date)
FROM daily_report r2
WHERE r2.inverter_id = r1.inverter_id
AND r2.day_offset = #{dayOffset}
)

SELECT * FROM daily_report
WHERE base_date
BETWEEN #{start} AND #{end}
AND day_offset = #{dayOffset}
